import{_ as o,o as t,c as d,ag as r,ah as a}from"./chunks/framework.D9bIGSBm.js";const h=JSON.parse('{"title":"记忆","description":"","frontmatter":{},"headers":[],"relativePath":"settings/memory.md","filePath":"settings/memory.md"}'),l={name:"settings/memory.md"};function s(n,e,i,c,m,u){return t(),d("div",null,[...e[0]||(e[0]=[r('<h1 id="记忆" tabindex="-1">记忆 <a class="header-anchor" href="#记忆" aria-label="Permalink to &quot;记忆&quot;">​</a></h1><p><strong>入口：</strong> 侧边栏 → <strong>设置</strong> → <strong>记忆</strong></p><p>记忆（Memory）页面集中管理 Claude / Codex / OpenCode / Kimi 用于长期记住项目约定与个人偏好的持久化指令文件（<code>CLAUDE.md</code> / <code>AGENTS.md</code>），以及 Claude 的 <strong>auto-memory</strong>（模型在对话过程中自动积累的分主题笔记）。</p><p>本页通过顶部 <strong>Claude | Codex | OpenCode | Kimi</strong> 切换栏分别维护各 CLI 的记忆文件（Kimi 家族自 v0.10.0 起纳入）。</p><p><img src="'+a+'" alt="截图：记忆设置页面，顶部 Claude/Codex/OpenCode 切换栏，下方分「全局记忆」「项目记忆」两组，项目记忆下方展示 AUTO-MEMORY 子列表"></p><hr><h2 id="全局记忆与项目记忆" tabindex="-1">全局记忆与项目记忆 <a class="header-anchor" href="#全局记忆与项目记忆" aria-label="Permalink to &quot;全局记忆与项目记忆&quot;">​</a></h2><p>页面按作用域分两组展示：</p><table tabindex="0"><thead><tr><th>作用域</th><th>说明</th><th>对应文件</th></tr></thead><tbody><tr><td><strong>全局记忆</strong></td><td>跨项目生效，存储在各 CLI 的用户级配置目录</td><td>Claude：<code>~/.claude/CLAUDE.md</code>；Codex：<code>~/.codex/AGENTS.md</code>；OpenCode：<code>~/.config/opencode/AGENTS.md</code>（遵循 <code>XDG_CONFIG_HOME</code> 环境变量，未设置时使用该默认路径）；Kimi：<code>~/.kimi-code/AGENTS.md</code></td></tr><tr><td><strong>项目记忆</strong></td><td>仅当前工作区生效；未打开工作区时该组显示提示「选择工作区任务后可查看项目记忆」</td><td>Claude：<code>&lt;工作区&gt;/CLAUDE.md</code>；Codex / OpenCode / Kimi：<code>&lt;工作区&gt;/AGENTS.md</code></td></tr></tbody></table><p>若对应文件已存在，显示一行记录（文件名、路径、文件大小），点击可打开详情弹窗；若尚未创建，显示「尚未创建」提示与<strong>新建</strong>按钮，点击即在目标路径创建一份空文件。</p><div class="tip custom-block"><p class="custom-block-title">Codex 的 override 文件优先</p><p>Codex 侧（全局或项目）若存在同目录下的 <code>AGENTS.override.md</code>，Codex CLI 实际读取的是这份 override 文件而非 <code>AGENTS.md</code>——本页会据此优先展示并编辑它。</p></div><hr><h2 id="auto-memory-仅-claude-·-项目记忆" tabindex="-1">AUTO-MEMORY（仅 Claude · 项目记忆） <a class="header-anchor" href="#auto-memory-仅-claude-·-项目记忆" aria-label="Permalink to &quot;AUTO-MEMORY（仅 Claude · 项目记忆）&quot;">​</a></h2><p>切到 <strong>Claude</strong> 且已打开工作区时，「项目记忆」组下方额外展示一个 <strong>AUTO-MEMORY</strong> 子列表——这是 Claude 在对话过程中自动写入的分主题记忆文件，路径为 <code>~/.claude/projects/&lt;项目编码路径&gt;/memory/</code>，与 Claude Code 自己读写的目录完全一致，因此这里看到的就是模型实际会加载的记忆。</p><ul><li>每条记录展示一个主题笔记的文件名与大小；其中索引文件 <code>MEMORY.md</code> 额外带<strong>索引</strong>徽标</li><li>页面顶部的搜索框按文件名或正文内容过滤，命中范围覆盖全局记忆、项目记忆与全部 auto-memory 笔记</li><li>点击<strong>新建记忆</strong>手动新建一个主题笔记：输入文件名（无需手动加 <code>.md</code> 后缀，应用会自动补齐，且会拒绝包含路径分隔符等非法字符的名称）后创建</li></ul><hr><h2 id="查看与编辑记忆文件" tabindex="-1">查看与编辑记忆文件 <a class="header-anchor" href="#查看与编辑记忆文件" aria-label="Permalink to &quot;查看与编辑记忆文件&quot;">​</a></h2><p>点击任意一条记忆记录，弹出详情弹窗：</p><ul><li>默认<strong>预览</strong>模式，以渲染后的 Markdown 展示内容（auto-memory 文件开头的 YAML frontmatter 会包成代码块展示，避免被 Markdown 误解析成加粗标题）</li><li>点击弹窗顶部的铅笔图标切换到<strong>编辑</strong>模式（Monaco 代码编辑器），修改后点击<strong>保存</strong>按钮或按 Ctrl+S 写回磁盘</li><li><strong>在文件管理器中显示</strong>图标可定位到系统文件管理器中的原文件</li><li>仅 auto-memory 笔记提供删除（垃圾桶图标）入口，点击后需二次确认，确认文案为「确定删除「{名称}」？文件将移入回收站。」；全局 / 项目主记忆文件（<code>CLAUDE.md</code> / <code>AGENTS.md</code>）不提供删除入口</li><li>有未保存改动时关闭弹窗会弹出「放弃未保存的修改？」确认，避免误丢改动</li></ul><hr><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="/docs/features/subagents.html">子智能体</a> — 另一种可复用配置：为特定任务派生专项 Agent</li><li><a href="/docs/settings/skills.html">技能</a> — 可通过 <code>/</code> 命令面板显式调用的专项工作流</li></ul>',22)])])}const p=o(l,[["render",s]]);export{h as __pageData,p as default};
